package arch.day9;

/**
 * Day 9 basic: throwable families, try/catch/finally cadence.
 */
public class Day9Basic {

    static void sep() {
        System.out.println("----------------------------------------");
    }

    public static void main(String[] args) {
        System.out.println("=== Throwable families ===");
        System.out.println("Exception -> checked environmental faults (often)");
        System.out.println("RuntimeException -> unchecked programmer bugs");
        System.out.println("Error -> JVM-level serious failures");
        sep();
        System.out.println("=== try / catch / finally order ===");
        System.out.println("try runs guarded work");
        System.out.println("catch handles matching throwables");
        System.out.println("finally runs before method returns");
        sep();
        System.out.println("=== try-with-resources idea ===");
        System.out.println("AutoCloseable closes in reverse; preserves suppressed exceptions");
        sep();
        System.out.println("=== parseInt lesson ===");
        System.out.println("NumberFormatException when digits invalid");
        sep();
        System.out.println("=== wrapping lesson ===");
        System.out.println("new IllegalStateException(msg, cause) keeps root stack");
        sep();
        System.out.println("=== custom cue ===");
        System.out.println("domain exceptions carry business fields for metrics");
        sep();
        System.out.println("=== review cue ===");
        System.out.println("never empty catch without comment and signal");
        sep();
        System.out.println("=== assignment cue ===");
        System.out.println("rehearse finally output from Day 9 assignment snippet");
        System.out.println("policy cue: OutOfMemoryError StackOverflowError belong to platform not feature catches");
        System.out.println("done");
    }
}

package arch.day9;

/**
 * Day 9 intermediate: parse guard, assignment finally trace, cause wrap, domain exception.
 */
public class Day9Intermediate {

    static int parseLenient(String s) {
        try {
            return Integer.parseInt(s.trim());
        } catch (NumberFormatException e) {
            return -1;
        }
    }

    static void printBanner() {
        System.out.println("banner: Day9 intermediate exception lab");
    }

    static void scenario1() {
        System.out.println("--- Scenario 1: NumberFormat guard ---");
        System.out.println("parse bad -> " + parseLenient("abc"));
        System.out.println("parse ok -> " + parseLenient("5"));
        System.out.println("parse blank -> " + parseLenient("   "));
    }

    static void scenario2() {
        System.out.println("--- Scenario 2: assignment try/catch/finally trace ---");
        try {
            System.out.println("try");
            if (true) {
                throw new RuntimeException();
            }
            System.out.println("after throw");
        } catch (RuntimeException e) {
            System.out.println("catch");
        } finally {
            System.out.println("finally");
        }
        System.out.println("after");
    }

    static void scenario3() {
        System.out.println("--- Scenario 3: wrap and preserve cause ---");
        try {
            Integer.parseInt("nope");
        } catch (NumberFormatException e) {
            IllegalStateException wrap = new IllegalStateException("wrap", e);
            System.out.println("causeClass=" + wrap.getCause().getClass().getSimpleName());
            System.out.println("message=" + wrap.getMessage());
        }
    }

    static class InsufficientStockException extends RuntimeException {
        final int requested;
        final int available;

        InsufficientStockException(int requested, int available) {
            super("need " + requested + " have " + available);
            this.requested = requested;
            this.available = available;
        }
    }

    static class Shelf {
        int stock = 10;

        void withdraw(int q) {
            if (q > stock) {
                throw new InsufficientStockException(q, stock);
            }
            stock -= q;
        }
    }

    static void scenario4() {
        System.out.println("--- Scenario 4: domain runtime exception ---");
        Shelf shelf = new Shelf();
        try {
            shelf.withdraw(99);
        } catch (InsufficientStockException e) {
            System.out.println("stockMsg=" + e.getMessage());
            System.out.println("requested=" + e.requested + " available=" + e.available);
        }
    }

    static void printFooter() {
        System.out.println("footer: map flows to Day9 assignment coding drills");
    }

    public static void main(String[] args) {
        printBanner();
        scenario1();
        scenario2();
        scenario3();
        scenario4();
        printFooter();
    }
}

package arch.day9;

/**
 * Day 9 advanced: suppressed exceptions idea, custom exception checklist, parsing playbook.
 */
public class Day9Advanced {

    static void spacer() {
        System.out.println("---");
    }

    static void preamble() {
        System.out.println("preface: three blocks for exception operations review");
        System.out.println("scope: production logging plus parsing boundaries");
    }

    static void block1() {
        System.out.println("=== Block 1: try-with-resources suppressed idea ===");
        System.out.println("primary: exception from try body");
        System.out.println("suppressed: exceptions from close() methods");
        System.out.println("API: Throwable.getSuppressed() since Java 7");
        System.out.println("ops tip: log both primary and suppressed in incident tickets");
        System.out.println("note: suppressed explains double faults during shutdown");
        System.out.println("note: prefer ARM over handwritten finally for Closeable");
        System.out.println();
    }

    static void block2() {
        System.out.println("=== Block 2: custom exception checklist ===");
        System.out.println("1) extend RuntimeException for programmer rule breaks");
        System.out.println("2) extend Exception when caller must handle recoverably");
        System.out.println("3) carry structured fields for metrics dashboards");
        System.out.println("4) message friendly for support desk templates");
        System.out.println("5) serialVersionUID when crossing JVM boundaries");
        System.out.println("6) avoid deep marker hierarchies without behaviour");
        System.out.println("7) document which layer translates JDBC to domain errors");
        System.out.println("8) add factory methods for consistent wording");
        System.out.println("9) pair message with error codes for automation");
        System.out.println("10) keep throwable names aligned with ubiquitous language");
        System.out.println();
    }

    static void block3() {
        System.out.println("=== Block 3: defensive parsing playbook ===");
        System.out.println("step | action");
        System.out.println("-----|------------------");
        System.out.println("1    | null check");
        System.out.println("2    | trim whitespace");
        System.out.println("3    | empty guard");
        System.out.println("4    | try parseInt");
        System.out.println("5    | catch NumberFormat return sentinel");
        System.out.println("6    | log at boundary if unexpected");
        System.out.println("7    | avoid parse inside hot loops without validation");
        System.out.println("8    | prefer Optional or Result types in functional layers");
        System.out.println("9    | integration tests for odd inputs if locale matters");
        System.out.println("10   | reject scientific notation unless specified");
        System.out.println("11   | document sentinel meaning (-1 demo exercise)");
        System.out.println("12   | surface validation to UI with field errors");
        System.out.println("review complete");
    }

    static void epilogue() {
        System.out.println("postscript: tie checklist to safeParseInt exercise");
        System.out.println("closing: rehearse checked vs unchecked elevator pitch");
        System.out.println("reminder: read getSuppressed after on-call redeploys");
        System.out.println("eof");
    }

    public static void main(String[] args) {
        System.out.println("banner: Day9 advanced exception lab");
        preamble();
        block1();
        spacer();
        block2();
        spacer();
        block3();
        epilogue();
    }
}

