package arch.day9;

/**
 * Day 9 exercise — maps to assignments_phase1.json Day 9 prompts.
 */
public class Day9Exercise {

    static class InsufficientStockException extends RuntimeException {
        private final int requested;
        private final int available;

        InsufficientStockException(int requested, int available) {
            super("Insufficient stock: requested " + requested + " but only " + available + " available");
            this.requested = requested;
            this.available = available;
        }

        int getRequested() {
            return requested;
        }

        int getAvailable() {
            return available;
        }
    }

    static class Inventory {
        private int stock = 10;

        void withdraw(int qty) {
            if (qty > stock) {
                throw new InsufficientStockException(qty, stock);
            }
            stock -= qty;
        }
    }

    static int safeParseInt(String s) {
        if (s == null || s.trim().isEmpty()) {
            return -1;
        }
        try {
            return Integer.parseInt(s.trim());
        } catch (NumberFormatException e) {
            return -1;
        }
    }

    public static void main(String[] args) {
        System.out.println("checked-note: IOException SQLException must be caught or declared via throws");
        System.out.println("unchecked-note: NullPointerException IllegalArgumentException are optional to handle");
        System.out.println("error-note: OutOfMemoryError StackOverflowError are JVM faults—not business catches");
        try {
            System.out.println("try");
            if (true) {
                throw new RuntimeException();
            }
            // System.out.println("after throw");
        } catch (RuntimeException e) {
            System.out.println("catch");
        } finally {
            System.out.println("finally");
        }
        System.out.println("after");

        Inventory inv = new Inventory();
        try {
            inv.withdraw(15);
        } catch (InsufficientStockException e) {
            System.out.println("stock:" + e.getMessage());
            System.out.println("stock-available:" + e.getAvailable());
        }

        System.out.println(safeParseInt("42"));
        System.out.println(safeParseInt("abc"));
        System.out.println(safeParseInt(null));
        System.out.println(safeParseInt(""));
        System.out.println(safeParseInt("  7  "));
    }
}

